    (224, '(Dialogo) A: "Sain kokeesta kympin!" / B: "Mahtavaa!"', 'phrase', 'f1466712551788b5b3e5b17536cc220d89202d08d523302772f48639399f857f', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_075", "note_culturale": "Reazione positiva e colloquiale a una buona notizia. ''Grande!'' / ''Mahtavaa!'' / ''Awesome!''."}', NULL),
    (225, '(Dialogo) A: "I got a 10 on the exam!" / B: "Awesome!"', 'phrase', '6d8aa11562703ca1321cc3e6c6ccbacda7a5cf6e374a6b9637430a2692014212', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_075", "note_culturale": "Reazione positiva e colloquiale a una buona notizia. ''Grande!'' / ''Mahtavaa!'' / ''Awesome!''."}', NULL),
    (226, '(Dialogo) A: "Ti ho portato un regalo dalla Finlandia." / B: "Ma dai! Non dovevi!"', 'phrase', 'ee6ef13816ff86d7a9ce29db54c56a706caf1900e8ce5204117bcf1ac9517a60', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_076", "note_culturale": "Reazione di sorpresa positiva a un regalo. ''Ma dai!'' / ''Ei ole totta!'' (forma standard) / ''No way!'' esprimono lo stesso stupore."}', NULL),
    (227, '(Dialogo) A: "Toin sinulle lahjan Suomesta." / B: "Ei ole totta! Ei olisi tarvinnut!"', 'phrase', 'c7ccbb8d0f71424d865e34cec6e99c768fb6cb8c981ea5932f75a763ecef6cce', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_076", "note_culturale": "Reazione di sorpresa positiva a un regalo. ''Ma dai!'' / ''Ei ole totta!'' (forma standard) / ''No way!'' esprimono lo stesso stupore."}', NULL),
    (228, '(Dialogo) A: "I brought you a gift from Finland." / B: "No way! You shouldn''t have!"', 'phrase', '5a01fdebe0e03492698d32a642f4986b2d1719f4dfe4b2663e9a350109c1e2e7', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_076", "note_culturale": "Reazione di sorpresa positiva a un regalo. ''Ma dai!'' / ''Ei ole totta!'' (forma standard) / ''No way!'' esprimono lo stesso stupore."}', NULL),
