    (233, '(Dialogo) A: "No, mitä mieltä olet?" / B: "Ei paha!"', 'phrase', '64c8f357ce9a9847469fe7692672c67790e4e94bd165596e00cc76c35844133d', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_078", "note_culturale": "Esprimere approvazione moderata. ''Niente male'' / ''Ei paha'' (Non male) / ''Not bad''."}', NULL),
