    (238, '(Dialogo) A: "Piove di nuovo." / B: "Uffa! Volevo uscire."', 'phrase', '29bfc107441e117e56048dfd9ac7be96008cbbea3a63fd941972853a5ac6ce3d', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_080", "note_culturale": "Reazione colloquiale negativa. ''Uffa!'' (IT), ''Voi ei!'' (FI), ''Ugh!'' (EN)."}', NULL),
