    (240, '(Dialogo) A: "It''s raining again." / B: "Ugh! I wanted to go out."', 'phrase', '0b10650461d1c98915893fd2a0e4c39450168f5819a15db203a10f0a38d0cab5', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_080", "note_culturale": "Reazione colloquiale negativa. ''Uffa!'' (IT), ''Voi ei!'' (FI), ''Ugh!'' (EN)."}', NULL),
    (241, '(Dialogo) A: "Ho dimenticato le chiavi." / B: "Accidenti! E ora?"', 'phrase', 'ad17143be0260d3ebb51d81f5698884861969a4d92fcc38646ca5f0da5019350', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_081", "note_culturale": "Esclamazione colloquiale per un problema. ''Accidenti!'' / ''Voi hitsi!'' (eufemismo) / ''Darn!''."}', NULL),
    (242, '(Dialogo) A: "Unohdin avaimet." / B: "Voi hitsi! Mitä nyt?"', 'phrase', '9ee8defedf2d6886fca1b97cbe9ceb3004f0e200f8938f28cdd22e8f66a32dd1', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_081", "note_culturale": "Esclamazione colloquiale per un problema. ''Accidenti!'' / ''Voi hitsi!'' (eufemismo) / ''Darn!''."}', NULL),
    (243, '(Dialogo) A: "I forgot the keys." / B: "Darn! Now what?"', 'phrase', 'adc0ef54397c266c5b33b53d0027653f31f32e30fe0bcefc4f25db15df1663b0', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_081", "note_culturale": "Esclamazione colloquiale per un problema. ''Accidenti!'' / ''Voi hitsi!'' (eufemismo) / ''Darn!''."}', NULL),
    (244, '(Dialogo) A: "Mi fa male la testa." / B: "Oh, poverino/a. Vuoi un''aspirina?"', 'phrase', '7cb784aa42d3e151809bc802cc5434b406157d1413dea4a6e8551aa2d3530254', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_082", "note_culturale": "Esprimere empatia per un piccolo malessere. ''Poverino/a'' / ''Voi raukkaa'' / ''Poor you''."}', NULL),
    (245, '(Dialogo) A: "Minulla on pää kipeä." / B: "Voi raukkaa. Haluatko aspiriinia?"', 'phrase', '57aaf49bede01c551b21ec93d3213f80d714593a10efcf45639bad6896f64ece', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_082", "note_culturale": "Esprimere empatia per un piccolo malessere. ''Poverino/a'' / ''Voi raukkaa'' / ''Poor you''."}', NULL),
    (246, '(Dialogo) A: "My head hurts." / B: "Oh, poor you. Do you want an aspirin?"', 'phrase', 'ac38feab55fc3386ea0021274a50251025e1d1f04b556b81e9404aef0328d4a8', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_082", "note_culturale": "Esprimere empatia per un piccolo malessere. ''Poverino/a'' / ''Voi raukkaa'' / ''Poor you''."}', NULL),
    (247, '(Dialogo) A: "Non trovo il telefono." / B: "Sei sicuro? Guarda bene."', 'phrase', '40012def1215b0266e90a54b4a73feaf0080da85bbb741dba134ec001be18c3d', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_083", "note_culturale": "Reazione standard a un oggetto smarrito."}', NULL),
    (248, '(Dialogo) A: "En löydä puhelintani." / B: "Oletko varma? Katso kunnolla."', 'phrase', 'ab301035f6c3911af5d65351d8bb3350f17d30256e36631c10fb9b444b1fc05d', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_083", "note_culturale": "Reazione standard a un oggetto smarrito."}', NULL),
    (249, '(Dialogo) A: "I can''t find my phone." / B: "Are you sure? Look properly."', 'phrase', 'd1dadbfefaa976c223e9871e9c34ed15d817054737613a607b7fd537ecde87b5', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_083", "note_culturale": "Reazione standard a un oggetto smarrito."}', NULL),
    (250, '(Dialogo) A: "Dobbiamo lavorare anche sabato." / B: "Che noia!"', 'phrase', '31b35065c9e8ea268332223e0dcc7ece808edad696ae2e6b042adaca3a736330', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_084", "note_culturale": "Esprimere noia o disappunto."}', NULL),
    (251, '(Dialogo) A: "Meidän täytyy työskennellä myös lauantaina." / B: "Onpa tylsää!"', 'phrase', 'f8db0184026222afcad18ed4177a86937ca0d3a4313ce7d3956b7dfe06afb38c', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_084", "note_culturale": "Esprimere noia o disappunto."}', NULL),
    (252, '(Dialogo) A: "We have to work on Saturday too." / B: "How boring!"', 'phrase', '290349062a19e28593834324eed4b48fec2eca908425d6878d0dd73a907b1924', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_084", "note_culturale": "Esprimere noia o disappunto."}', NULL),
    (253, '(Dialogo) A: "Non mi piace questo film." / B: "Nemmeno a me."', 'phrase', '1dc7d7c77f8a9681d231083b35934af1545cbefd0d17b3e9a74272194e7d568f', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_085", "note_culturale": "Esprimere accordo negativo."}', NULL),
    (254, '(Dialogo) A: "En pidä tästä elokuvasta." / B: "En minäkään."', 'phrase', 'eaf45b874a3273a697bea7285870cd4819cdcfcb3d30c229e12d9fdc54b6191b', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_085", "note_culturale": "Esprimere accordo negativo."}', NULL),
    (255, '(Dialogo) A: "I don''t like this movie." / B: "Me neither."', 'phrase', 'bad8c9596b7eaec69575618ab1e2a57a5e1c4c12c571c1a0a799d08020694747', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_085", "note_culturale": "Esprimere accordo negativo."}', NULL),
    (256, '(Dialogo) A: "Il treno è in ritardo." / B: "Di nuovo? Che palle!"', 'phrase', '5d4438383a8f9d12d7e61b1fe83235b72223d4da406ec0b786f33d2d59852180', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_087", "note_culturale": "Reazione frustrata. ''Che palle!'' (IT, volgare colloquiale) si traduce con l''eufemismo ''Voi hitsi!'' (FI) o ''What a pain!'' (EN)."}', NULL),
    (257, '(Dialogo) A: "Juna on myöhässä." / B: "Taasko? Voi hitsi!"', 'phrase', 'd3ee35926dbfd7408d493b9a0828525efbdb3c669b7a86150834d44d38053d9a', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_087", "note_culturale": "Reazione frustrata. ''Che palle!'' (IT, volgare colloquiale) si traduce con l''eufemismo ''Voi hitsi!'' (FI) o ''What a pain!'' (EN)."}', NULL),
    (258, '(Dialogo) A: "The train is late." / B: "Again? What a pain!"', 'phrase', '94360fc03b9128bbcd46d562e22d23fde344ab7e34ddae9a20771e85c227f3ab', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_087", "note_culturale": "Reazione frustrata. ''Che palle!'' (IT, volgare colloquiale) si traduce con l''eufemismo ''Voi hitsi!'' (FI) o ''What a pain!'' (EN)."}', NULL),
    (259, '(Dialogo) A: "Non funziona internet." / B: "Ma dai! Proprio adesso."', 'phrase', '2acc210d9398a446093a49075df97c0a20fcc3a65094be10a21a5ca686dd942f', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_088", "note_culturale": "Reazione di sorpresa negativa. ''Ma dai!'' / ''Ei ole totta!'' (Non è vero!) / ''No way!''."}', NULL),
    (260, '(Dialogo) A: "Internetyhteys ei toimi." / B: "Ei ole totta! Juuri nyt."', 'phrase', 'f1b4d9a24477c39bafd77837a56c052f7db73423aaac5b6815f0fdca740a2578', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_088", "note_culturale": "Reazione di sorpresa negativa. ''Ma dai!'' / ''Ei ole totta!'' (Non è vero!) / ''No way!''."}', NULL),
    (261, '(Dialogo) A: "The internet isn''t working." / B: "No way! Right now."', 'phrase', '0862b09ad719f2e2a7e7767dce07441e66ba444a8dffe09d1eccf969d8a78bc1', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_088", "note_culturale": "Reazione di sorpresa negativa. ''Ma dai!'' / ''Ei ole totta!'' (Non è vero!) / ''No way!''."}', NULL),
    (262, '(Dialogo) A: "Cosa c''è? Sembri triste." / B: "Sono solo un po'' giù."', 'phrase', 'a4b04f50d32f566e5efca2e0dfdbce4b18cdc2bad860d18366dae85524a835f7', 'A1', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_089", "note_culturale": "Modo idiomatico A1/A2 per esprimere tristezza. ''Essere giù'' / ''olla allapäin'' / ''to be down''."}', NULL),
    (263, '(Dialogo) A: "Mikä hätänä? Näytät surulliselta." / B: "Olen vain vähän allapäin."', 'phrase', '5b824b4966e04d7af1a9096981922ad5636a7b93e07e1bd50605bbc0e44096f2', 'A1', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_089", "note_culturale": "Modo idiomatico A1/A2 per esprimere tristezza. ''Essere giù'' / ''olla allapäin'' / ''to be down''."}', NULL),
    (264, '(Dialogo) A: "What''s wrong? You look sad." / B: "I''m just a bit down."', 'phrase', '4f20da6c92de2473a28a1eb29da7c74e0647e9521f0526b1d445a0221c25d444', 'A1', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_089", "note_culturale": "Modo idiomatico A1/A2 per esprimere tristezza. ''Essere giù'' / ''olla allapäin'' / ''to be down''."}', NULL),
    (265, '(Dialogo) A: "Prendi l''ombrello!" / B: "Sì, piove a catinelle!"', 'phrase', '0052ec474664aeac9497a4159742244f2bb2b800ad67676ba5ec0d79e745e74c', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_090", "note_culturale": ""}', NULL),
    (266, '(Dialogo) A: "Ota sateenvarjo!" / B: "Joo, sataa kaatamalla!"', 'phrase', 'f8478472606d75fd0e1e8908373a7e3473e4c2e886f23ca4d65c46b5db012611', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_090", "note_culturale": ""}', NULL),
    (267, '(Dialogo) A: "Take the umbrella!" / B: "Yeah, it''s raining cats and dogs!"', 'phrase', '4a0832a780300ab90aa5e0e9b4f012cfaa17b1d80c629a78d3cef4b75181c736', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_090", "note_culturale": ""}', NULL),
    (268, '(Dialogo) A: "Metti la sciarpa." / B: "Sì, fa un freddo cane."', 'phrase', '60dd1a242a262ebf80f97634c11daab2ed903512627b1c81d949086a2f656269', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_091", "note_culturale": ""}', NULL),
    (269, '(Dialogo) A: "Laita kaulaliina." / B: "Joo, on koiranilma."', 'phrase', '1df819325cf6a307a027ea2c7a0f452ced781dfb5b772972917fce7ed67e5647', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_091", "note_culturale": ""}', NULL),
    (270, '(Dialogo) A: "Wear your scarf." / B: "Yeah, it''s freezing cold."', 'phrase', 'da3451305b15afd80e8090e083b23a37571b38cc6603376cc62158dc8c14fbc5', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_091", "note_culturale": ""}', NULL),
    (271, '(Dialogo) A: "Accendi l''aria condizionata!" / B: "Subito, si muore di caldo!"', 'phrase', '1979248c379859a454736a9fd21cd9348857de35f762dca810c84358a2cf3ec6', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_092", "note_culturale": ""}', NULL),
    (272, '(Dialogo) A: "Laita ilmastointi päälle!" / B: "Heti, täällä on hiostavan kuuma!"', 'phrase', '660169c25324ab801ae3ab2cee3aa9029ae89a340425c8003e4a53f3c7f37740', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_092", "note_culturale": ""}', NULL),
    (273, '(Dialogo) A: "Turn on the AC!" / B: "Right away, it''s boiling hot!"', 'phrase', 'b86095f35e5806f3fdd05610e9fcbaa6722708c679544d0913ff7f566f9403d8', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_092", "note_culturale": ""}', NULL),
    (274, '(Dialogo) A: "Andiamo al mare?" / B: "Sì, c''è un sole che spacca le pietre!"', 'phrase', 'e749de6e63fe2dc79b4072535e2cb1e4a6b047ece1833e482ae70090842717bb', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_093", "note_culturale": ""}', NULL),
    (275, '(Dialogo) A: "Mennäänkö rannalle?" / B: "Joo, aurinko porottaa kunnolla!"', 'phrase', 'd59a957aac55d85621827bc2c07950273f21305f8ffc46b85708cfceabfd1042', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_093", "note_culturale": ""}', NULL),
    (276, '(Dialogo) A: "Let''s go to the beach?" / B: "Yeah, the sun is blazing!"', 'phrase', '7ca943b0312e2211d3c20a3dc069e3f5780a8b491e31b9d2959b0301e4d76c54', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_093", "note_culturale": ""}', NULL),
    (277, '(Dialogo) A: "Guarda fuori..." / B: "Mamma mia, è un tempo da lupi. Meglio restare a casa."', 'phrase', '52aa2a34fa9b751f203e1c53357f7ee90af88771783a648129972cfc12d53ddb', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_094", "note_culturale": ""}', NULL),
    (278, '(Dialogo) A: "Katso ulos..." / B: "Voi hyvä tavaton, on kamala ilma. Parempi pysyä kotona."', 'phrase', 'a9f618ba15ee4a539cb1578889e08fd217610d4515ee4141eeda45f28f193a89', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_094", "note_culturale": ""}', NULL),
    (279, '(Dialogo) A: "Look outside..." / B: "Wow, it''s awful weather. Better stay home."', 'phrase', 'c3c53c6db310436021ea7bce0500aeaf2f1e479f5b2800cdee2b400a39ffe4fc', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_094", "note_culturale": ""}', NULL),
    (280, '(Dialogo) A: "Piove." / B: "Ma no, è solo una nuvola passeggera."', 'phrase', 'a4a9c64eccfc573294630aed380578dbbc62e0f3616d46d70d538a6f7550f26d', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_095", "note_culturale": ""}', NULL),
    (281, '(Dialogo) A: "Sataa." / B: "Ei se mitään, se on vain ohimenevä pilvi."', 'phrase', 'a1636766eb06df6d65ad9e0c7f220ebdcd4bcefd362ff3b8763dad5fc1edc2bd', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_095", "note_culturale": ""}', NULL),
    (282, '(Dialogo) A: "It''s raining." / B: "Nah, it''s just a passing cloud."', 'phrase', '0ee819db1ff5b5f390b12f9cba02cfb6606584b174725dd6855952d0bcc49f96', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_095", "note_culturale": ""}', NULL),
    (283, '(Dialogo) A: "Aspettiamo qui." / B: "Sì, sta diluviando."', 'phrase', 'a13587b243100967b5b9f59a6179fcad32d9e0217d10bdce99bd5c01a2fa9771', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_096", "note_culturale": ""}', NULL),
    (284, '(Dialogo) A: "Odotetaan tässä." / B: "Joo, vettä tulee kuin aisaa."', 'phrase', '305da638c25a16a2c270e87ce4572c4d596f3ab88603b12999fafbfd0af3cd6b', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_096", "note_culturale": ""}', NULL),
    (285, '(Dialogo) A: "Let''s wait here." / B: "Yeah, it''s pouring."', 'phrase', 'db320179d8de9772c59e0ed0a4a191e3d17b744b6e781085db523de9fd6db55a', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_096", "note_culturale": ""}', NULL),
    (286, '(Dialogo) A: "Non respiro." / B: "Hai ragione, c''è un''afa terribile."', 'phrase', '713bc97e9f8604b1adf92d63276f1d59c22b6901c847c3d2280c840cf394df0e', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_097", "note_culturale": ""}', NULL),
