    (335, '(Dialogo) A: "Oletko lukenut kokeeseen?" / B: "Joo, vietin koko viikonlopun kirjojen parissa."', 'phrase', '1feaf37b60f588f6f428d834032b7524eb9ff543b85ca700f0a6838cbd620109', 'A2', true, 'easy', 'firebase', 2, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_113", "note_culturale": ""}', NULL),
    (336, '(Dialogo) A: "Did you study for the test?" / B: "Yeah, I spent all weekend hitting the books."', 'phrase', '6df52b6f9e0812d4407f9edfa1131be0ee7cb3426bb7be52df22bfa12fce2d36', 'A2', true, 'easy', 'firebase', 3, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_113", "note_culturale": ""}', NULL),
    (337, '(Dialogo) A: "Oggi ho preso 10 in matematica!" / B: "Tanta roba! Complimenti!"', 'phrase', '786bfcfcccc29d1bb3fd39876053f4ede004ecb100e53ff2f8606c644bb8b041', 'A2', true, 'easy', 'firebase', 1, NULL, '{"source": "firebase", "import_date": "2026-03-06", "original_id": "frase_114", "note_culturale": ""}', NULL),
